import { DFA, NFA, createDFA, createNFA, intersection, union, resetStateCounter, EPSILON, RegexToNFA } from '../finite-automata';

function ezDFA(){const d=new DFA('ev');d.addState('ev',true);d.addState('od',false);d.addTransition('ev','0','od');d.addTransition('ev','1','ev');d.addTransition('od','0','ev');d.addTransition('od','1','od');return d;}
function eoD(){const d=new DFA('ev');d.addState('ev',true);d.addState('od',false);d.addTransition('ev','1','od');d.addTransition('ev','0','ev');d.addTransition('od','1','ev');d.addTransition('od','0','od');return d;}
function ewAB(){const n=new NFA('q0');n.addState('q0',false);n.addState('q1',false);n.addState('q2',true);n.addTransition('q0','a','q0');n.addTransition('q0','b','q0');n.addTransition('q0','a','q1');n.addTransition('q1','b','q2');return n;}

